+                0o644,
+                0,
+                0,
+            )
+            .unwrap();
+        ops.write(
+            &cx,
+            &mut RequestScope::empty(),
+            attr.ino,
+            0,
+            b"hello world!",
+        )
+        .unwrap();
+
+        // Set size to current size (no-op).
+        let same = ops
+            .setattr(
+                &cx,
+                &mut RequestScope::empty(),
+                attr.ino,
+                &SetAttrRequest {
+                    size: Some(12),
+                    ..Default::default()
+                },
+            )
+            .unwrap();
+        assert_eq!(same.size, 12);
+
+        let data = ops
+            .read(&cx, &mut RequestScope::empty(), attr.ino, 0, 4096)
+            .unwrap();
+        assert_eq!(data, b"hello world!");
+    }
